(()=>{'use strict';
const $=s=>document.querySelector(s),$$=s=>[...document.querySelectorAll(s)];
const T=v=>String(v??'').trim(),N=v=>Number(String(v??'').replace(/,/g,''))||0;
const F=n=>N(n).toLocaleString('th-TH'),B=n=>N(n).toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2});
const U=a=>[...new Set((a||[]).map(T).filter(Boolean))];
const E=s=>T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
let rows=[],meta={},key='';
function dlabel(s){const p=T(s).split('-');return p.length===3?`${p[2]}/${p[1]}/${p[0]}`:(s||'ทั้งหมด')}
function normRows(a){return(a||[]).map(r=>({date:T(r.date),inv:T(r.inv),type:T(r.type)||'INVC',ps:T(r.ps)||'ไม่ระบุ PS',store:T(r.store)||'ไม่ระบุร้าน',tele:T(r.tele),isTele:!!r.isTele,code:T(r.code),sku:T(r.sku)||'ไม่ระบุสินค้า',brand:T(r.brand)||'ไม่ระบุแบรนด์',size:T(r.size)||'ไม่ระบุไซซ์',qty:N(r.qty),unit:N(r.unit),amt:N(r.amt)}))}
function state(){try{return JSON.parse(localStorage.getItem('doit-json:'+key)||'{}')||{}}catch{return{}}}
function filters(){const s=state();return{start:$('#startDate')?.value||s.filters?.start||'',end:$('#endDate')?.value||s.filters?.end||'',ps:$('#psSelect')?.value||s.filters?.ps||'',brand:$('#brandSelect')?.value||s.filters?.brand||'',type:$('#typeSelect')?.value||s.filters?.type||'',q:$('#q')?.value||s.filters?.q||'',receiver:$('#storeSelect')?.value||s.receiver||''}}
function base(){const f=filters(),q=T(f.q).toLowerCase();return rows.filter(r=>(!f.start||r.date>=f.start)&&(!f.end||r.date<=f.end)&&(!f.ps||r.ps===f.ps)&&(!f.brand||r.brand===f.brand)&&(!f.type||r.type===f.type)&&(!q||[r.date,r.inv,r.code,r.sku,r.store,r.ps,r.brand,r.size,r.type,r.tele].join(' ').toLowerCase().includes(q)))}
function group(rs,byStore=false){const m=new Map();rs.forEach(r=>{const pk=[r.brand,r.size,r.code||r.sku,r.sku,r.type].join('|'),k=byStore?[r.store,pk].join('|'):pk;let x=m.get(k);if(!x){x={poolKey:pk,store:byStore?r.store:'',brand:r.brand,size:r.size,code:r.code,sku:r.sku,type:r.type,qty:0,amt:0,unit:r.unit||0,bills:new Set(),stores:new Map()};m.set(k,x)}x.qty+=N(r.qty);x.amt+=N(r.amt);x.unit=x.qty&&x.amt?x.amt/x.qty:x.unit;x.bills.add(r.inv);x.stores.set(r.store,(x.stores.get(r.store)||0)+N(r.qty))});return[...m.values()].sort((a,b)=>(a.store||'').localeCompare(b.store||'','th')||a.brand.localeCompare(b.brand,'th')||a.size.localeCompare(b.size,'th')||a.sku.localeCompare(b.sku,'th'))}
function rkey(pk,rec){const f=filters();return[f.start,f.end,f.ps,f.brand,f.type,rec,pk].join('|')}
function sumMap(map,pk){let s=0,p='|'+pk;Object.keys(map||{}).forEach(k=>{if(k.endsWith(p))s+=N(map[k])});return s}
function remain(g){const s=state();return N(g.qty)-sumMap(s.send,g.poolKey)+sumMap(s.add,g.poolKey)-sumMap(s.pull,g.poolKey)}
function setMsg(s){const m=$('#msg');if(m)m.textContent=s}
function copySummary(){const s=state(),pool=group(base()),f=filters(),sent=Object.values(s.send||{}).reduce((a,v)=>a+N(v),0);const txt=`DOIT JSON/index\nไฟล์ ${meta.file_name||'-'}\nวันที่ ${dlabel(f.start)} - ${dlabel(f.end)}\nPS ${f.ps||'ทั้งหมด'}\nร้านปัจจุบัน ${f.receiver||'-'}\nรายการ ${F(pool.length)}\nจำนวนส่งจริงรวม ${F(sent)} ชิ้น`;navigator.clipboard?.writeText(txt);setMsg('Copy สรุป JSON แล้ว')}
function exportCsv(){const s=state(),pool=group(base()),out=[['receiver','brand','size','sku_code','product','type','order_qty','send_qty','add_qty','pull_qty','remain_all']];U(Object.keys({...s.send,...s.add,...s.pull}).map(k=>k.split('|')[5]).filter(Boolean)).forEach(rec=>pool.forEach(g=>{const k=rkey(g.poolKey,rec);if(N(s.send?.[k])||N(s.add?.[k])||N(s.pull?.[k]))out.push([rec,g.brand,g.size,g.code,g.sku,g.type,g.qty,N(s.send?.[k]),N(s.add?.[k]),N(s.pull?.[k]),remain(g)])}));const csv='\ufeff'+out.map(a=>a.map(x=>'"'+String(x??'').replace(/"/g,'""')+'"').join(',')).join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv;charset=utf-8'}));a.download='doit-json-receiver-orders.csv';a.click();setMsg('Export CSV JSON แล้ว')}
function packBills(bills){const cap=257,baseH=32,lineH=7,maxLines=Math.max(1,Math.floor((cap-baseH)/lineH)),small=[],pages=[];bills.forEach(b=>{for(let i=0;i<b.lines.length;i+=maxLines){const part={...b,lines:b.lines.slice(i,i+maxLines)};part.h=baseH+part.lines.length*lineH;if(b.lines.length>maxLines)pages.push({items:[part],used:cap});else small.push(part)}});small.sort((a,b)=>b.h-a.h);small.forEach(b=>{let best=null,space=1e9;pages.forEach(p=>{let r=cap-p.used;if(b.h<=r&&r-b.h<space){best=p;space=r-b.h}});if(best){best.items.push(b);best.used+=b.h}else pages.push({items:[b],used:b.h})});return pages}
function preparePrint(){const s=state(),pool=group(base()),by={};Object.keys(s.send||{}).forEach(k=>{const rec=k.split('|')[5],pk=k.split('|').slice(6).join('|'),qty=N(s.send[k]);if(!rec||qty<=0)return;const g=pool.find(x=>x.poolKey===pk);if(!g)return;(by[rec]??=[]).push({sku:g.code||'',name:g.sku,qty,unit:g.unit||0})});const f=filters(),bills=Object.entries(by).map(([store,lines])=>({store,ps:f.ps||U(base().map(r=>r.ps)).join(', '),date:dlabel(f.end||f.start),lines}));if(!bills.length){alert('ยังไม่ได้ใส่จำนวนส่งจริงให้ร้านใด');return}const data=JSON.stringify(packBills(bills));const w=window.open('','_blank');if(!w){alert('เบราว์เซอร์บล็อกหน้าปริ้น');return}w.document.write(`<!doctype html><html lang="th"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>เตรียมปริ้นบิล</title><style>@page{size:A4 portrait;margin:8mm}*{box-sizing:border-box}body{margin:0;background:#e5e7eb;font-family:system-ui,'Segoe UI',Tahoma,sans-serif;color:#111827}.bar{position:sticky;top:0;background:#0b6b31;color:#fff;padding:10px;display:flex;gap:8px;align-items:center;z-index:9}.bar button{border:0;border-radius:8px;padding:9px 14px;font-weight:900}.pages{padding:10px}.page{width:194mm;min-height:281mm;background:white;margin:0 auto 10px;padding:0;page-break-after:always;box-shadow:0 6px 20px #0002}.bill{padding:6mm 7mm;border-bottom:1px dashed #999;break-inside:avoid}.bill:last-child{border-bottom:0}.head{display:flex;justify-content:space-between;gap:8px;border-bottom:1px solid #111;padding-bottom:4px;margin-bottom:5px}.title{font-size:16px;font-weight:950}.meta{font-size:11px;line-height:1.4}.shop{font-size:15px;font-weight:950;margin:3px 0 5px}.tbl{width:100%;border-collapse:collapse;font-size:11px}.tbl th,.tbl td{border:1px solid #222;padding:3px 4px}.tbl th{background:#f3f4f6}.r{text-align:right}.c{text-align:center}.price{width:22mm;border:0;border-bottom:1px solid #111;text-align:right;font:inherit}.total{display:flex;justify-content:flex-end;gap:10mm;font-weight:950;margin-top:4px;font-size:12px}.sign{display:grid;grid-template-columns:1fr 1fr 1fr;gap:8mm;margin-top:8mm;font-size:11px;text-align:center}.sign div{border-top:1px solid #111;padding-top:2mm}@media print{body{background:white}.bar{display:none}.pages{padding:0}.page{box-shadow:none;margin:0;width:auto;min-height:auto}.bill{break-inside:avoid}}</style></head><body><div class="bar"><b>เตรียมปริ้นบิล A4 อัตโนมัติ</b><button onclick="window.print()">ปริ้น</button></div><div class="pages" id="pages"></div><script>const pages=${data};function money(n){return (Number(n)||0).toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2})}function draw(){document.getElementById('pages').innerHTML=pages.map((p,pi)=>'<section class="page">'+p.items.map(b=>{let body=b.lines.map((l,i)=>'<tr><td class="c">'+(i+1)+'</td><td>'+l.sku+'</td><td>'+l.name+'</td><td class="r">'+l.qty+'</td><td class="r"><input class="price" data-q="'+l.qty+'" value="'+money(l.unit)+'"></td><td class="r amt">'+money(l.qty*l.unit)+'</td></tr>').join('');return '<div class="bill"><div class="head"><div><div class="title">ใบส่งสินค้า</div><div class="shop">'+b.store+'</div></div><div class="meta">วันที่: '+b.date+'<br>เซลล์: '+b.ps+'<br>หน้า: '+(pi+1)+'</div></div><table class="tbl"><thead><tr><th>#</th><th>รหัส</th><th>รายการสินค้า</th><th>จำนวน</th><th>ราคา/หน่วย</th><th>รวม</th></tr></thead><tbody>'+body+'</tbody></table><div class="total"><span>รวมชิ้น: <b class="qty"></b></span><span>รวมเงิน: <b class="sum"></b></span></div><div class="sign"><div>ผู้จัดของ</div><div>ผู้ส่ง</div><div>ผู้รับสินค้า</div></div></div>'}).join('')+'</section>').join('');calc()}function calc(){document.querySelectorAll('.bill').forEach(b=>{let q=0,s=0;b.querySelectorAll('.price').forEach(inp=>{let qty=Number(inp.dataset.q)||0,unit=Number(String(inp.value).replace(/,/g,''))||0,amt=qty*unit;q+=qty;s+=amt;inp.closest('tr').querySelector('.amt').textContent=money(amt)});b.querySelector('.qty').textContent=q.toLocaleString('th-TH');b.querySelector('.sum').textContent=money(s)})}document.addEventListener('input',e=>{if(e.target.className==='price')calc()});draw();<\/script></body></html>`);w.document.close()}
function drawDist(){const f=filters(),gs=group(base().filter(r=>!f.receiver||r.store===f.receiver),true),shown=gs.slice(0,200);let h='<thead><tr><th>#</th><th>ร้านที่คีย์</th><th>SKU</th><th>สินค้า</th><th>จำนวนคีย์</th><th>บิล</th><th>ยอด</th><th>ประเภท</th></tr></thead><tbody>';shown.forEach((g,i)=>h+=`<tr><td>${i+1}</td><td>${E(g.store)}</td><td>${E(g.code||'-')}</td><td class="p"><b>${E(g.sku)}</b><small>${E(g.brand)} · ${E(g.size)}</small></td><td>${F(g.qty)}</td><td>${F(g.bills.size)}</td><td>${B(g.amt)}</td><td>${E(g.type)}</td></tr>`);if(!shown.length)h+='<tr><td colspan="8" class="empty">ไม่พบข้อมูลร้านที่คีย์</td></tr>';$('#table').innerHTML=h+'</tbody>';$('#tableCount').textContent='JSON/index ตรวจร้านที่คีย์ '+F(gs.length)+' รายการ';setTabs('distTab')}
function drawRaw(){const rs=base(),shown=rs.slice(0,200);let h='<thead><tr><th>#</th><th>วันที่</th><th>บิล</th><th>SKU</th><th>สินค้า</th><th>ร้านที่คีย์</th><th>PS</th><th>จำนวน</th><th>ยอด</th><th>ประเภท</th></tr></thead><tbody>';shown.forEach((r,i)=>h+=`<tr><td>${i+1}</td><td>${E(dlabel(r.date))}</td><td>${E(r.inv)}</td><td>${E(r.code||'-')}</td><td class="p"><b>${E(r.sku)}</b><small>${E(r.brand)} · ${E(r.size)}</small></td><td>${E(r.store)}</td><td>${E(r.ps)}</td><td>${F(r.qty)}</td><td>${B(r.amt)}</td><td>${E(r.type)}</td></tr>`);if(!shown.length)h+='<tr><td colspan="10" class="empty">ไม่พบรายการดิบ</td></tr>';$('#table').innerHTML=h+'</tbody>';$('#tableCount').textContent='JSON/index รายการดิบ '+F(rs.length)+' แถว';setTabs('rawTab')}
function setTabs(on){['modePick','distTab','shipTab','doneTab','rawTab'].forEach(id=>$('#'+id)?.classList.toggle('on',id===on))}
function tele(){const trs=rows.filter(r=>r.isTele);const btn=$('#teleBillsBtn');if(btn){btn.textContent='บิล Telesale ('+F(new Set(trs.map(r=>[r.inv,r.store,r.tele,r.date].join('|'))).size)+')';btn.onclick=()=>{const body=$('#teleBody');if(!body)return;const m=new Map();trs.forEach(r=>{const k=[r.inv,r.store,r.tele,r.date].join('|');let b=m.get(k);if(!b){b={...r,lines:[],qty:0,amt:0};m.set(k,b)}b.lines.push(r);b.qty+=N(r.qty);b.amt+=N(r.amt)});const bills=[...m.values()];body.innerHTML=bills.length?bills.map(b=>`<section class="teleBill"><div class="teleBillHead"><div class="store">ร้าน: ${E(b.store)}</div><div class="meta">เลขบิล/ออเดอร์: <b>${E(b.inv)}</b> · วันที่: ${E(dlabel(b.date))}<br>เทเลเซลล์: ${E(b.tele||'ไม่ระบุ')}</div></div><table class="teleTbl"><thead><tr><th>#</th><th>SKU</th><th>สินค้า</th><th>จำนวน</th><th>ราคา</th><th>ยอด</th></tr></thead><tbody>${b.lines.map((r,i)=>`<tr><td>${i+1}</td><td>${E(r.code||'-')}</td><td>${E(r.sku)}</td><td>${F(r.qty)}</td><td>${B(r.unit)}</td><td>${B(r.amt)}</td></tr>`).join('')}</tbody></table></section>`).join(''):'<div class="teleEmpty">ไม่พบรายการ Telesale ใน JSON นี้</div>';$('#teleShade')?.classList.add('on');$('#teleDrawer')?.classList.add('on')}}}
function bind(){if($('#copySummary'))$('#copySummary').onclick=copySummary;if($('#exportCsv'))$('#exportCsv').onclick=exportCsv;if($('#prepPrint'))$('#prepPrint').onclick=preparePrint;if($('#distTab'))$('#distTab').onclick=drawDist;if($('#rawTab'))$('#rawTab').onclick=drawRaw;if($('#shipTab'))$('#shipTab').onclick=()=>{setTabs('shipTab');preparePrint()};tele()}
function patch(){if(!window.DOIT_JSON_APP||window.DOIT_JSON_APP.__fix265)return false;const orig=window.DOIT_JSON_APP.load;window.DOIT_JSON_APP.load=function(payload,m={}){rows=normRows(Array.isArray(payload)?payload:(payload.rows||[]));meta=m||{};key=m.id||payload.version_id||m.file_name||Date.now();orig.call(window.DOIT_JSON_APP,payload,m);setTimeout(bind,0);setTimeout(bind,500)};window.DOIT_JSON_APP.__fix265=true;return true}
if(!patch()){let n=0,t=setInterval(()=>{if(patch()||++n>40)clearInterval(t)},100)}
})();
